package com.chaobo.scm.supplier.infrastructure.persistence.profile;

import org.apache.ibatis.annotations.*;import java.util.List;
@Mapper public interface SupplierAdmissionQueryMapper {record Row(long id,String no,String code,String name,String taxNo,String type,String contact,String mobile,String settlement,int status,String reject,int version){}@Select("SELECT admission_id id,admission_no no,candidate_supplier_code code,candidate_supplier_name name,tax_no taxNo,supplier_type type,contact_name contact,contact_mobile mobile,settlement_json settlement,admission_status status,reject_reason reject,version FROM sup_supplier_admission WHERE admission_id=#{id} AND deleted=0")Row find(long id);@Select("<script>SELECT COUNT(*) FROM sup_supplier_admission WHERE deleted=0 <if test=\"status != null\">AND admission_status=#{status}</if><if test=\"keyword != null and keyword != ''\">AND (admission_no LIKE CONCAT('%',#{keyword},'%') OR candidate_supplier_name LIKE CONCAT('%',#{keyword},'%') OR candidate_supplier_code LIKE CONCAT('%',#{keyword},'%'))</if></script>")long count(@Param("status")Integer status,@Param("keyword")String keyword);@Select("<script>SELECT admission_id id,admission_no no,candidate_supplier_code code,candidate_supplier_name name,tax_no taxNo,supplier_type type,contact_name contact,contact_mobile mobile,settlement_json settlement,admission_status status,reject_reason reject,version FROM sup_supplier_admission WHERE deleted=0 <if test=\"status != null\">AND admission_status=#{status}</if><if test=\"keyword != null and keyword != ''\">AND (admission_no LIKE CONCAT('%',#{keyword},'%') OR candidate_supplier_name LIKE CONCAT('%',#{keyword},'%') OR candidate_supplier_code LIKE CONCAT('%',#{keyword},'%'))</if> ORDER BY updated_at DESC LIMIT #{offset},#{size}</script>")List<Row> page(@Param("status")Integer status,@Param("keyword")String keyword,@Param("offset")int offset,@Param("size")int size);}
